function coerceControl(f) {
  // mode and aux_follow are autosaved through their own change-handlers
  // (dashboard mode dropdown and SYSTEM tab aux-follow dropdown), so
  // they are intentionally excluded from the TARGETS form patch.
  return {
    target_beer_f:      getVal(f, "target_beer_f", "number"),
    target_ambient_f:   getVal(f, "target_ambient_f", "number"),
    hysteresis_f:       getVal(f, "hysteresis_f", "number"),
    ramp_slope_fph:     getVal(f, "ramp_slope_fph", "number"),
    ramp_target_f:      getVal(f, "ramp_target_f", "number"),
    crash_target_f:     getVal(f, "crash_target_f", "number"),
  };
}

function coerceSystem(f) {
  // Minutes come in from the UI; store seconds on the wire so the
  // control loop can use raw values without unit-conversion math.
  // Round to the nearest whole second so the stored value stays clean.
  const minToSec = (min) => (typeof min === "number" && !Number.isNaN(min))
    ? Math.round(min * 60) : null;
  return {
    system: {
      polling_interval_s:     getVal(f, "polling_interval_s", "int"),
      units:                  getVal(f, "units"),
      timezone_offset_hours:  getVal(f, "timezone_offset_hours", "number"),
      beer_sensor_rom:        getVal(f, "beer_sensor_rom"),
      ambient_sensor_rom:     getVal(f, "ambient_sensor_rom"),
      relay_active_low:       getVal(f, "relay_active_low", "boolean"),
    },
    compressor: {
      cooling_dwell_time_s:       minToSec(getVal(f, "_comp_cooling_dwell_time_min",      "number")),
      max_cool_runtime_s:         minToSec(getVal(f, "_comp_max_cool_runtime_min",        "number")),
      fail_safe_shutdown_time_s:  minToSec(getVal(f, "_comp_fail_safe_shutdown_time_min", "number")),
    },
    safety: {
      beer_emergency_temp_high_f:    getVal(f, "_safety_beer_emergency_temp_high_f",    "number"),
      beer_emergency_temp_low_f:     getVal(f, "_safety_beer_emergency_temp_low_f",     "number"),
      ambient_emergency_temp_high_f: getVal(f, "_safety_ambient_emergency_temp_high_f", "number"),
      ambient_emergency_temp_low_f:  getVal(f, "_safety_ambient_emergency_temp_low_f",  "number"),
    },
  };
}

function coerceAlerts(f) {
