/**
 * Show the PID Reset-to-Defaults confirmation modal.
 * Resolves true on confirm, false on cancel / Escape.
 * Outside-click does NOT dismiss -- same rule as the OTA modal.
 */
function showPidResetModal() {
  return new Promise(resolve => {
    const modal     = $("#pid-reset-modal");
    const btnOk     = $("#pid-reset-modal-confirm");
    const btnCancel = $("#pid-reset-modal-cancel");
    if (!modal || !btnOk || !btnCancel) {
      resolve(false);
      return;
    }
    modal.classList.remove("hidden");

    const cleanup = (choice) => {
      modal.classList.add("hidden");
      btnOk.removeEventListener("click", onOk);
      btnCancel.removeEventListener("click", onCancel);
      document.removeEventListener("keydown", onKey);
      resolve(choice);
    };
    const onOk     = () => cleanup(true);
    const onCancel = () => cleanup(false);
    const onKey    = (e) => { if (e.key === "Escape") cleanup(false); };

    btnOk.addEventListener("click", onOk);
    btnCancel.addEventListener("click", onCancel);
    document.addEventListener("keydown", onKey);
  });
}

