function setupActions() {
  $("#btn-start").addEventListener("click", async () => {
    await api("/api/control/start", { method: "POST" });
  });
  $("#btn-stop").addEventListener("click", async () => {
    await api("/api/control/stop", { method: "POST" });
  });

  // Autosave the dashboard mode dropdown.  The control loop re-reads
  // cfg.control.mode every tick, so the change takes effect on the next
  // interval without a Run/Stop cycle.
  const modeSel = $("#dash-mode-select");
  if (modeSel) {
    modeSel.addEventListener("change", async () => {
      const chosen = modeSel.value;
      try {
        await api("/api/config", {
          method: "PUT",
          body:   JSON.stringify({ control: { mode: chosen } }),
        });
      } catch (e) {
        console.error("[mode] save failed:", e);
      }
    });
  }

  // Autosave the Aux Follow dropdown on the SYSTEM tab.  aux_follow lives
  // under cfg.control, so the patch targets /api/config directly.
  const auxSel = $("#aux-follow-select");
  if (auxSel) {
    auxSel.addEventListener("change", async () => {
      try {
        await api("/api/config", {
          method: "PUT",
          body:   JSON.stringify({ control: { aux_follow: auxSel.value } }),
        });
      } catch (e) {
        console.error("[aux_follow] save failed:", e);
      }
    });
  }
  $("#btn-reset-ramp").addEventListener("click", async () => {
    await api("/api/control/reset-ramp", { method: "POST" });
  });
  $("#btn-reset-crash").addEventListener("click", async () => {
    await api("/api/control/reset-crash", { method: "POST" });
  });

  const rescan = async () => {
    await api("/api/sensors/scan", { method: "POST" });
    await loadSensors();
  };
  $("#btn-rescan-beer").addEventListener("click", rescan);
  $("#btn-rescan-ambient").addEventListener("click", rescan);

  $("#btn-test-email").addEventListener("click", async () => {
    const msg = $("#alerts-msg");
    try {
      await api("/api/alerts/test", { method: "POST" });
      flash(msg, true, "Test email sent.");
    } catch (e) {
      flash(msg, false, e.message);
    }
  });

  $("#btn-load-sessions").addEventListener("click", async () => {
    const sel = $("#bf-session-select");
    const msg = $("#api-msg");
    // Sessions list also blocks Microdot for a few seconds -- wrap in
    // withLongOp so the ONLINE pill stays green during the fetch.
    await withLongOp(async () => {
      // 20 s: the Pico's outbound HTTPS to api.brewersfriend.com plus
      // the SSL handshake on cold connections can push well past the
      // default 4 s browser abort.  Match the Pico's own 15 s server-
      // side timeout plus a small margin.
      const busy = beginBusy(msg, "Loading sessions...");
      try {
        const r = await api("/api/api-service/sessions", { timeoutMs: 20000 });
        sel.innerHTML = "";
        sel.add(new Option("\u2014 select \u2014", ""));
        r.sessions.forEach(s => sel.add(new Option(s.title || s.id, s.id)));
        const chosen = currentConfig.api.brewersfriend.session_id;
        if (chosen) sel.value = chosen;
        endBusy(busy, true, `Loaded ${r.sessions.length} session(s).`);
      } catch (e) {
        endBusy(busy, false, `Load sessions failed: ${e.message}`);
      }
    });
  });

  $("#bf-session-select").addEventListener("change", async ev => {
    const opt = ev.target.selectedOptions[0];
    if (!opt || !opt.value) return;
    // Session-select triggers an immediate outbound BF fetch on the
    // Pico (refresh_current), which blocks Microdot for a few seconds.
    // Wrap in withLongOp so the ONLINE pill stays green.
    await withLongOp(async () => {
      const busy = beginBusy($("#api-msg"), "Selecting session...");
      try {
        await api("/api/api-service/select-session", {
          method: "POST",
          body: JSON.stringify({ session_id: opt.value, session_title: opt.textContent }),
          timeoutMs: 20000,
        });
        endBusy(busy, true, "Session selected \u2014 history cleared.");
        await loadConfig();
        // Wipe the stale ring-buffer cache -- the Pico just cleared
        // its side and any local analysis would be pointing at the
        // wrong session.  refreshRingBufferCache re-fetches the (now
        // empty) history and re-runs analyze, which will show the
        // "Pending" state until the user clicks Refresh History.
        fgRingBuffer    = null;
        fgLastResult    = null;
        fgLastRingFetch = 0;
        await refreshRingBufferCache();
      } catch (e) {
        endBusy(busy, false, `Session select failed: ${e.message}`);
      }
    });
  });

  $("#btn-refresh-fg").addEventListener("click", async () => {
    const msg = $("#api-msg");
    // Refresh does 15-30 s of synchronous HTTPS on the Pico and
    // blocks its Microdot event loop.  Wrap in withLongOp so the
    // ONLINE indicator doesn't flap to OFFLINE while we wait.
    await withLongOp(async () => {
      const busy = beginBusy(msg, "Refreshing history...");
      try {
        // Refresh drives fetch_recent_readings on the Pico (v13+): one
        // /brewsessions call to anchor the window + one /fermentation
        // call with ?from=<today-window_days> to pull just that window.
        // Two round-trips totalling ~5-15 s on a fresh heap.  60 s
        // headroom keeps us clear of TLS handshake stalls on the Pico
        // without letting a truly hung request block the UI forever.
        const r = await api("/api/api-service/refresh", {
          method: "POST",
          timeoutMs: 60000,
        });
        const elapsed = Math.floor((Date.now() - busy.start) / 1000);
        // Distinguish three outcomes:
        //   1. Clean refresh -- fetched N, persisted N.
        //   2. Partial fetch that would have SHRUNK the buffer --
        //      Pico refused to overwrite, kept the existing (larger)
        //      dataset.  Amber-adjacent warning, not a hard error.
        //   3. Empty fetch (0 readings) with existing buffer intact --
        //      same message shape as case 2 but wording tweaked.
        if (r.partial && r.kept_existing) {
          endBusy(busy, false,
            `Partial fetch (${r.fetched} of ${r.readings}) \u2014 kept existing buffer (${elapsed}s).`);
        } else if (r.fetched === 0 && r.kept_existing) {
          endBusy(busy, false,
            `Fetched 0 readings \u2014 kept existing buffer of ${r.readings} (${elapsed}s).`);
        } else {
          endBusy(busy, true, `Refreshed ${r.readings} readings in ${elapsed}s.`);
        }
        // Pull the newly-persisted ring buffer down and re-run local
        // analysis so the FG card reflects the fresh dataset without
        // waiting on the periodic tick.
        await refreshRingBufferCache();
      } catch (e) {
        endBusy(busy, false, `Refresh failed: ${e.message}`);
      }
    });
  });

  $("#btn-analyze-fg").addEventListener("click", async () => {
    const el = $("#fg-result");
    // Run Analysis always fetches a fresh ring buffer -- the button's
    // intent is "give me the current answer NOW", so honouring a cached
    // ring buffer (however recent) violates user expectation, especially
    // right after a Pico-side auto-refresh has landed but the browser's
    // ring-buffer cache is technically still "fresh" by the 30-min
    // FG_RING_REFRESH_MS threshold.  Cost is one small HTTP call --
    // negligible compared to the analysis it enables.
    el.textContent = "Running analysis...";
    try {
      // fetchRingBuffer throws on failure so the user gets a real
      // error message ("timeout", "HTTP 500", etc.) instead of the
      // fallback "No ring buffer available" that a silent failure
      // would otherwise land on.
      await fetchRingBuffer();
      if (!Array.isArray(fgRingBuffer) || fgRingBuffer.length === 0) {
        el.textContent = "Ring buffer is empty. Click Refresh History first.";
        return;
      }
      // Re-run analysis against the just-fetched buffer with current
      // config (so unsaved tolerance/window/outlier tweaks take effect
      // immediately in the diagnostics panel).
      const result = FG.analyze(
        fgRingBuffer,
        (currentConfig && currentConfig.api && currentConfig.api.fg) || {},
      );
      fgLastResult = result;
      const cls    = FG.classify(result);
      el.textContent = renderFgDiagnostics({
        ...result,
        classification: cls,
      });
      el.scrollIntoView({ behavior: "smooth", block: "nearest" });
    } catch (e) {
      el.textContent = "Error: " + e.message;
    }
  });

  // WiFi reset is now hardware-only: hold the GP7 reset button on the
  // Pico for 4 seconds to wipe credentials and reboot into provisioning.
  // The browser-side button was removed to eliminate any accidental
  // remote reset path from the UI.  The /api/wifi/reset endpoint is
  // preserved on the server for emergency access via curl.

  $("#btn-refresh-log").addEventListener("click", refreshLog);

  $("#btn-ota-check").addEventListener("click", checkForUpdates);
  $("#btn-ota-install").addEventListener("click", installUpdate);
  $("#btn-ota-reload").addEventListener("click", reloadNow);

  const forceBtn = $("#btn-ota-force-reinstall");
  if (forceBtn) forceBtn.addEventListener("click", forceReinstall);
}


async function forceReinstall() {
  const ok = confirm(
    "Force Reinstall will clear the Pico's cached list of installed files.\n\n" +
    "The next Check for Updates -> Install will push every file in the " +
    "release, even ones whose contents haven't changed.\n\n" +
    "Continue?"
  );
  if (!ok) return;

  const btn = $("#btn-ota-force-reinstall");
  const originalText = btn ? btn.textContent : "";
  if (btn) {
    btn.disabled = true;
    btn.textContent = "Clearing cache...";
  }

  try {
    const res = await fetch("/api/ota/manifest", {
      method:  "PUT",
      headers: { "Content-Type": "application/json" },
      body:    JSON.stringify({}),
      signal:  AbortSignal.timeout(5000),
    });
    if (!res.ok) throw new Error(`HTTP ${res.status}`);
    appendOtaLog("[OTA] Cache cleared -- next Install will push all files.");
    if (btn) btn.textContent = "Cache Cleared";
    setTimeout(() => {
      if (btn) {
        btn.textContent = originalText;
        btn.disabled = false;
      }
    }, 2500);
  } catch (e) {
    appendOtaLog(`[OTA] Failed to clear cache: ${e.message || e}`);
    alert(`Failed to clear cache: ${e.message || e}`);
    if (btn) {
      btn.textContent = originalText;
      btn.disabled = false;
    }
  }
}

