/* -------------------- OTA update client -------------------- */

const OTA_REPO       = "keglevelmonitor/keglevelpico";
const OTA_BASE       = `https://raw.githubusercontent.com/${OTA_REPO}/main/ota/fermvault`;
// 4 KB per /api/update POST.  Started at 8 KB but a multi-file install
// with a fragmented heap could OOM the Pico while it was reading the
// base64-decoded chunk into RAM and writing it to flash.  4 KB roughly
// halves the peak per-request footprint (parsed dict + string content)
// and doubles the number of round-trips -- a small latency price for
// a large reliability win, especially when combined with the removal
// of the per-chunk config_manager.flush_state() call (see server.py).
const OTA_CHUNK      = 4096;
const OTA_TIMEOUT_MS = 15000;  // per-request ceiling -- Pico flash writes take up to ~5 s on big files

let otaAvailable  = null;   // { manifest, bundleUrl, version } once check succeeds
let otaInProgress = false;
let otaLog        = [];

function setOtaLog(lines) {
  otaLog = Array.isArray(lines) ? lines.slice() : [String(lines)];
  $("#updates-log").textContent = otaLog.join("\n");
}

function appendOtaLog(line) {
  otaLog.push(line);
  const el = $("#updates-log");
  el.textContent = otaLog.join("\n");
  el.scrollTop = el.scrollHeight;
}

function setOtaProgress(fraction) {
  const pct = Math.max(0, Math.min(1, fraction)) * 100;
  $("#ota-progress-fill").style.width = `${pct.toFixed(1)}%`;
}

function setOtaButtonsBusy(busy) {
  $("#btn-ota-check").disabled   = busy;
  $("#btn-ota-install").disabled = busy || !otaAvailable;
}

/**
 * Show a large unmissable status box beneath the progress bar so the
 * user isn't left squinting at scrolling log text.  Kind:
 *   "success"  — green,  used after new version verified
 *   "warning"  — amber,  used for version mismatch
 *   "failure"  — red,    used for timeout / write failure
 *   null / ""  — hides the banner
 */
function setOtaBanner(kind, mainText, subText = "") {
  const el = $("#ota-banner");
  el.classList.remove("success", "warning", "failure", "hidden");
  if (!kind) {
    el.classList.add("hidden");
    el.innerHTML = "";
    return;
  }
  el.classList.add(kind);
  const sub = subText ? `<div class="banner-countdown">${subText}</div>` : "";
  el.innerHTML = `<div>${mainText}</div>${sub}`;
}

function showReloadButton() {
  $("#btn-ota-reload").classList.remove("hidden");
}

function hideReloadButton() {
  $("#btn-ota-reload").classList.add("hidden");
}

function reloadNow() {
  // Cache-busting reload — bypass browser cache so the new HTML/JS/CSS
  // is fetched from the freshly-updated Pico even if the browser cached
  // the old versions.
  window.location.reload(true);
}

function parseVersion(str) {
  const m = (str || "").match(/^(\d+)\.(\d+)\.(\d+)/);
  return m ? [parseInt(m[1], 10), parseInt(m[2], 10), parseInt(m[3], 10)] : [0, 0, 0];
}

function versionNewer(a, b) {
  for (let i = 0; i < 3; i++) {
    if (a[i] > b[i]) return true;
    if (a[i] < b[i]) return false;
  }
  return false;
}

async function sha256Hex(data) {
  const buf = typeof data === "string" ? new TextEncoder().encode(data) : data;
  if (typeof crypto !== "undefined" && crypto.subtle) {
    const hash = await crypto.subtle.digest("SHA-256", buf);
    return Array.from(new Uint8Array(hash))
      .map(b => b.toString(16).padStart(2, "0")).join("");
  }
  return null;   // crypto.subtle only exposed over HTTPS / localhost — plain-HTTP falls back
}

/**
 * Order files so that the *last* write can trigger reboot without stranding
 * the Pico in an unusable state:
 *   1. server.py         — server logic first (won't apply until reboot)
 *   2. lib/*             — Microdot framework
 *   3. www/*             — web UI (harmless to swap while running)
 *   4. other src/*.py    — the rest
 *   5. main.py           — LAST, because it's what boots the whole thing
 *
 * If main.py were written first and had an import error, the Pico would
 * refuse to come back up.  Writing it last means every dependency is
 * already in place by the time we reboot.
 */
function sortOtaFiles(files) {
  const rank = p => {
    if (p === "server.py")   return 0;
    if (p.startsWith("lib/")) return 1;
    if (p.startsWith("www/")) return 2;
    if (p === "main.py")     return 4;
    return 3;
  };
  return [...files].sort((a, b) => rank(a.path) - rank(b.path));
}

async function checkForUpdates() {
  if (otaInProgress) return;
  setOtaButtonsBusy(true);
  otaAvailable = null;
  setOtaProgress(0);
  setOtaBanner(null);
  hideReloadButton();
  setOtaLog(["Checking for updates..."]);

  try {
    const vRes = await fetch("/api/version", { signal: AbortSignal.timeout(8000) });
    const vData = vRes.ok ? await vRes.json() : null;
    const currentVer = parseVersion(vData && vData.version);
    appendOtaLog(`Pico firmware:  ${vData && vData.version || "?"}`);

    const mRes = await fetch(`${OTA_BASE}/manifest.json`,
                             { signal: AbortSignal.timeout(10000) });
    if (!mRes.ok) throw new Error(`Manifest download failed (${mRes.status})`);
    const manifest = await mRes.json();
    const latestVer = parseVersion(manifest.version);
    appendOtaLog(`Latest release: ${manifest.version} (${manifest.build_date || "?"})`);

    if (versionNewer(latestVer, currentVer)) {
      otaAvailable = {
        manifest,
        bundleUrl: `${OTA_BASE}/bundle.json`,
        version:   manifest.version,
      };
      appendOtaLog("");
      appendOtaLog(`Update available: ${manifest.version}`);

      // Best-effort changelog display.  Absent changelog / network error
      // is non-fatal — the update is still installable.
      try {
        const clRes = await fetch(`${OTA_BASE}/changelog.json`,
                                  { signal: AbortSignal.timeout(8000) });
        if (clRes.ok) {
          const changelog = await clRes.json();
          const relevant = (changelog || []).filter(e =>
            versionNewer(parseVersion(e.version), currentVer));
          if (relevant.length) {
            appendOtaLog("");
            appendOtaLog("What's new:");
            relevant.slice(0, 15).forEach(e => {
              appendOtaLog(`  ${e.version} (${e.date || "?"})`);
              String(e.notes || "").split("\n").forEach(line => {
                if (line.trim()) appendOtaLog(`    ${line.trim()}`);
              });
            });
          }
        }
      } catch (_) { /* changelog is nice-to-have */ }
    } else {
      appendOtaLog("");
      appendOtaLog("Firmware is up to date.");
    }
  } catch (e) {
    appendOtaLog("");
    appendOtaLog(`Error: ${e.message || e}`);
  } finally {
    setOtaButtonsBusy(false);
  }
}

/**
 * Show the "monitoring is active" modal and resolve with the user's
 * choice: "resume" (stop, update, restart monitoring), "leave" (stop,
 * update, leave stopped), or "cancel" (abort the update).
 *
 * Escape key resolves as "cancel".  Clicking anywhere outside the card
 * intentionally does NOT dismiss — the user must pick a concrete action
 * so we never enter an ambiguous "did they mean cancel?" state.
 */
function showMonitoringModal(mode) {
  return new Promise(resolve => {
    const modal  = $("#ota-monitoring-modal");
    const modeEl = $("#ota-modal-mode");
    modeEl.textContent = (mode || "monitoring").toUpperCase();
    modal.classList.remove("hidden");

    const btnResume = $("#ota-modal-resume");
    const btnLeave  = $("#ota-modal-leave");
    const btnCancel = $("#ota-modal-cancel");

    const cleanup = (choice) => {
      modal.classList.add("hidden");
      btnResume.removeEventListener("click", onResume);
      btnLeave .removeEventListener("click", onLeave);
      btnCancel.removeEventListener("click", onCancel);
      document.removeEventListener("keydown", onKey);
      resolve(choice);
    };
    const onResume = () => cleanup("resume");
    const onLeave  = () => cleanup("leave");
    const onCancel = () => cleanup("cancel");
    const onKey    = (e) => { if (e.key === "Escape") cleanup("cancel"); };

    btnResume.addEventListener("click", onResume);
    btnLeave .addEventListener("click", onLeave);
    btnCancel.addEventListener("click", onCancel);
    document.addEventListener("keydown", onKey);

    // Default focus on the recommended action so Enter-to-confirm works.
    setTimeout(() => btnResume.focus(), 0);
  });
}

async function installUpdate() {
  if (!otaAvailable || otaInProgress) return;
  const { manifest, bundleUrl, version } = otaAvailable;

  otaInProgress = true;
  setOtaButtonsBusy(true);
  setOtaProgress(0);
  setOtaBanner(null);
  hideReloadButton();

  // If monitoring is currently active, ask the user how to handle it
  // before writing anything.  Three choices: auto-resume after reboot,
  // leave it stopped, or cancel the update entirely.  Everything from
  // here on threads `postInstallAction` through the flow so waitForReboot
  // can act on it on the success path.
  let postInstallAction = "none";  // "none" | "resume" | "leave"
  try {
    const preState = await api("/api/state", { timeoutMs: 5000 });
    const c = preState && preState.control;
    if (c && c.monitoring_active) {
      const modeBefore = (c.mode || "monitoring").toString();
      const choice = await showMonitoringModal(modeBefore);
      if (choice === "cancel") {
        appendOtaLog("[OTA] Install cancelled by user (monitoring left running).");
        // Pre-check runs BEFORE the main install try/finally, so we
        // have to reset install-in-progress state ourselves here.
        otaInProgress = false;
        setOtaButtonsBusy(false);
        return;
      }
      postInstallAction = choice;                // "resume" or "leave"
      appendOtaLog("");
      appendOtaLog(`[OTA] Stopping monitoring (was ${modeBefore.toUpperCase()})...`);
      try {
        await api("/api/control/stop", { method: "POST", timeoutMs: 5000 });
        // Small settle so the control loop finishes its current tick and
        // releases relays before we start blasting files at the Pico.
        await new Promise(r => setTimeout(r, 500));
        appendOtaLog("[OTA] Monitoring stopped.");
      } catch (e) {
        appendOtaLog(`[OTA] Warning: stop request failed (${e.message || e}).  Proceeding anyway; the server-side 409 guard will catch it if still active.`);
      }
    }
  } catch (e) {
    // Pre-check itself failed — fall through and let the install attempt
    // proceed.  The server's 409 guard on /api/update is our safety net.
    console.warn("[OTA] Monitoring pre-check failed:", e);
  }

  try {
    appendOtaLog("");
    appendOtaLog(`[OTA] Downloading firmware ${version}...`);
    const bRes = await fetch(bundleUrl, { signal: AbortSignal.timeout(30000) });
    if (!bRes.ok) throw new Error(`Bundle download failed (${bRes.status})`);
    const bundleText = await bRes.text();

    // Whole-bundle integrity check.  Skipped if crypto.subtle is
    // unavailable (plain-HTTP page), which is common for Pico access —
    // that's fine, we still have per-file server-side atomicity.
    if (manifest.bundle_sha256) {
      appendOtaLog("[OTA] Verifying firmware integrity...");
      const got = await sha256Hex(bundleText);
      if (got === null) {
        appendOtaLog("[OTA] SHA256 verification skipped (requires HTTPS).");
      } else if (got.toLowerCase() !== manifest.bundle_sha256.toLowerCase()) {
        appendOtaLog("[OTA] SHA256 mismatch — aborting.  No files were changed.");
        appendOtaLog(`  Expected: ${manifest.bundle_sha256.slice(0, 16)}...`);
        appendOtaLog(`  Got:      ${got.slice(0, 16)}...`);
        return;
      } else {
        appendOtaLog("[OTA] Integrity verified.");
      }
    }

    const bundle = JSON.parse(bundleText);
    const allFiles = sortOtaFiles(bundle.files || []);
    if (allFiles.length === 0) {
      appendOtaLog("[OTA] Error: firmware bundle contains no files.");
      return;
    }

    // Diff against the Pico's cached OTA manifest to skip files whose
    // SHA-256 hasn't changed since the last install.  First install
    // (endpoint absent / empty) pushes everything.
    let oldHashes = {};
    try {
      const omRes = await fetch("/api/ota/manifest",
                                { signal: AbortSignal.timeout(5000) });
      if (omRes.ok) {
        const oldManifest = await omRes.json();
        for (const f of (oldManifest.files || [])) oldHashes[f.path] = f.sha256;
      }
    } catch (_) { /* first OTA or endpoint missing — push all */ }

    const newHashes = {};
    for (const f of (manifest.files || [])) newHashes[f.path] = f.sha256;
    const files = allFiles.filter(f => {
      const oh = oldHashes[f.path];
      const nh = newHashes[f.path];
      return !oh || !nh || oh !== nh;
    });
    const skipped = allFiles.length - files.length;
    if (skipped > 0) appendOtaLog(`[OTA] ${skipped} file(s) unchanged — skipping.`);
    if (files.length === 0) {
      appendOtaLog("[OTA] Nothing to install.  Firmware already in sync.");
      return;
    }

    // Persist the NEW manifest to the PENDING slot BEFORE writing any
    // files.  main.py at boot promotes pending -> live only if
    // FIRMWARE_VERSION matches the pending manifest's version -- so
    // the "live" ota_manifest.json always describes the version
    // actually running.  Non-critical if the PUT fails (worst case:
    // next OTA check pushes all files fresh).
    try {
      await fetch("/api/ota/pending_manifest", {
        method:  "PUT",
        headers: { "Content-Type": "application/json" },
        body:    JSON.stringify(manifest),
        signal:  AbortSignal.timeout(5000),
      });
    } catch (_) { /* non-critical */ }

    appendOtaLog(`[OTA] Pushing ${files.length} file(s) to Pico...`);
    for (let i = 0; i < files.length; i++) {
      const f = files[i];
      const isLast = i === files.length - 1;
      appendOtaLog(`[OTA] Writing ${f.path} (${i + 1}/${files.length})...`);
      setOtaProgress((i + 0.5) / files.length);

      // Chunk large files (microdot.py ~60 KB) to stay under Pico's
      // request-body ceiling and RAM budget.
      const chunks = [];
      if (f.content.length > OTA_CHUNK) {
        for (let off = 0; off < f.content.length; off += OTA_CHUNK) {
          chunks.push(f.content.substring(off, off + OTA_CHUNK));
        }
      } else {
        chunks.push(f.content);
      }

      const lastIdx = chunks.length - 1;

      for (let c = 0; c < chunks.length; c++) {
        const isFinalChunkOfFinalFile = isLast && c === lastIdx;

        const payload = JSON.stringify({
          filename: f.path,
          content:  chunks[c],
          append:   c > 0,
          reboot:   isFinalChunkOfFinalFile,
        });
        const res = await fetch("/api/update", {
          method:  "POST",
          headers: { "Content-Type": "application/json" },
          body:    payload,
          signal:  AbortSignal.timeout(OTA_TIMEOUT_MS),
        });
        if (!res.ok) {
          const errBody = await res.json().catch(() => ({}));
          const errMsg  = errBody.error || res.statusText;
          if (res.status === 409) {
            appendOtaLog("[OTA] Monitoring is active.  Stop monitoring and try again.");
            setOtaBanner("failure",
              "Install aborted — monitoring is active",
              "Stop monitoring on the Dashboard, then click Install again.");
          } else {
            appendOtaLog(`[OTA] Failed on ${f.path}: ${errMsg}`);
            setOtaBanner("failure",
              `Install failed while writing ${f.path}`,
              errMsg);
          }
          return;
        }
      }
      setOtaProgress((i + 1) / files.length);
    }

    appendOtaLog("[OTA] All files written.  Pico is rebooting...");
    await waitForReboot(version, postInstallAction);
  } catch (e) {
    if (e.name === "AbortError" || e.name === "TimeoutError") {
      appendOtaLog("[OTA] Request timed out.  The Pico may be rebooting.");
      await waitForReboot(version, postInstallAction);
    } else {
      appendOtaLog(`[OTA] Error: ${e.message || e}`);
      setOtaBanner("failure", "Install failed", e.message || String(e));
    }
  } finally {
    otaInProgress = false;
    otaAvailable  = null;
    setOtaButtonsBusy(false);
  }
}

async function waitForReboot(expectedVersion, postInstallAction = "none") {
  appendOtaLog("[OTA] Waiting for Pico to come back online...");
  const maxAttempts = 20;
  const delayMs = 3000;
  await new Promise(r => setTimeout(r, 4000));
  for (let i = 0; i < maxAttempts; i++) {
    try {
      const res = await fetch("/api/version",
                              { signal: AbortSignal.timeout(3000) });
      if (res.ok) {
        const data = await res.json();
        const newVer = data.version || "?";
        $("#updates-version").textContent = newVer;
        $("#updates-build").textContent   = data.build_date || "--";
        appendOtaLog(`[OTA] Pico is back online.  Firmware: ${newVer}`);
        setOtaProgress(1);

        if (expectedVersion && newVer === expectedVersion) {
          appendOtaLog(`[OTA] Update complete.  Firmware ${newVer} verified.`);

          // Post-install monitoring handling.  Fires only on the verified-
          // success path — never on a mismatched or missing version, since
          // we don't want to auto-start into an unknown firmware state.
          if (postInstallAction === "resume") {
            appendOtaLog("[OTA] Restarting monitoring...");
            try {
              await fetch("/api/control/start", {
                method:  "POST",
                headers: { "Content-Type": "application/json" },
                signal:  AbortSignal.timeout(5000),
              });
              appendOtaLog("[OTA] Monitoring resumed.");
            } catch (e) {
              appendOtaLog("[OTA] Auto-resume failed -- start monitoring manually from the Dashboard.");
            }
          } else if (postInstallAction === "leave") {
            appendOtaLog("[OTA] Monitoring left stopped as requested.  Start it from the Dashboard when ready.");
          }

          showReloadButton();
          await autoReloadCountdown(5, `Update complete — firmware ${newVer}`);
        } else if (expectedVersion) {
          appendOtaLog(`[OTA] Warning: expected ${expectedVersion} but Pico reports ${newVer}.`);
          setOtaBanner("warning",
            `Version mismatch — expected ${expectedVersion}, Pico reports ${newVer}`,
            "Click Reload Now to load whatever version the Pico is running.");
          showReloadButton();
        }
        return;
      }
    } catch (_) { /* still rebooting */ }
    await new Promise(r => setTimeout(r, delayMs));
  }
  appendOtaLog("[OTA] Pico did not respond after reboot.  Check power + WiFi.");
  setOtaBanner("failure",
    "Pico did not come back online",
    "Check the Pico's power and WiFi, then try Reload Now once it responds.");
  showReloadButton();
}

/**
 * Show a green banner with a live "Reloading in N..." countdown and then
 * reload the page.  The user can click "Reload Now" to skip the wait, or
 * navigate away — the countdown is intentionally short (5 s) so the
 * outcome is unmissable without being annoying.
 */
async function autoReloadCountdown(seconds, mainText) {
  for (let s = seconds; s > 0; s--) {
    setOtaBanner("success", mainText, `Reloading in ${s}...`);
    await new Promise(r => setTimeout(r, 1000));
  }
  setOtaBanner("success", mainText, "Reloading now...");
  reloadNow();
}


/* -------------------- boot -------------------- */

(async function main() {
  setupTabs();
  setupForms();
  setupActions();
  // Native browser prompt if the user tries to close/reload the tab while
  // any settings form has unsaved edits.  Modern browsers ignore the
  // custom message and show their own text; assignment to returnValue is
  // still required to trigger the prompt.
  window.addEventListener("beforeunload", (e) => {
    if (anyDirty()) {
      e.preventDefault();
      e.returnValue = "";
    }
  });
  await loadConfig().catch(e => console.error("config load failed", e));
  poll();
  // Watchdog runs faster than the poll interval so the pill flips promptly
  // (within ~1s of the STALE_MS threshold) instead of waiting for the next
  // poll cycle to notice the timeout.
  setInterval(watchdog, 1000);
  // Initial ring-buffer fetch + local FG analysis.  Fire-and-forget --
  // the Pico is still coming up in poll() and we don't want to block
  // the first paint.  A failed initial fetch just means the FG card
  // shows the last-known state.fg (from the Pico's report-back cache)
  // until the periodic tick tries again.
  refreshRingBufferCache().catch(e =>
    console.warn("[FG] initial history fetch failed:", e && e.message));
  // Periodic refresh so the browser's cached ring buffer stays in step
  // with the Pico's without user interaction.  A 60 s check with a
  // 5-minute effective refresh gives us "the FG card doesn't go
  // stale" without hammering /api/api-service/history.
  setInterval(fgAnalysisTick, 60 * 1000);
})();

/* FermVault Brain — dark theme with orange accent */

* { box-sizing: border-box; }

body {
  margin: 0;
  font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
  background: #0a0a0a;
  color: #e0e0e0;
  min-height: 100vh;
}

#app {
  width: 100%;
  max-width: 960px;
  margin: 0 auto;
  min-height: 100vh;
  display: flex;
  flex-direction: column;
}

/* -------------------------------------------------------------------------
   Header
   ------------------------------------------------------------------------- */

.main-header {
  display: flex;
  align-items: center;
  gap: 12px;
  padding: 0 16px;
  height: 54px;
  background: #141414;
  border-bottom: 1px solid #222;
}

.main-header h1 {
  margin: 0;
  font-size: 20px;
  font-weight: 700;
  color: #ffa500;
  letter-spacing: 0.5px;
}

.status-pill {
  font-size: 11px;
  font-weight: 700;
  padding: 3px 10px;
  border-radius: 20px;
  letter-spacing: 0.5px;
}
.status-pill.online  { background: #14351f; color: #4ade80; }
.status-pill.offline { background: #351414; color: #f87171; }

.version {
  margin-left: auto;
  font-size: 11px;
  color: #666;
  letter-spacing: 0.5px;
}

/* -------------------------------------------------------------------------
   Nav
   ------------------------------------------------------------------------- */

.top-nav {
  display: flex;
  flex-wrap: wrap;
  background: #101010;
  border-bottom: 1px solid #222;
}

.nav-btn {
  flex: 1;
  min-width: 90px;
  padding: 12px 6px;
  border: none;
  background: transparent;
  color: #999;
  font-size: 12px;
  font-weight: 700;
  letter-spacing: 0.6px;
  cursor: pointer;
  border-bottom: 2px solid transparent;
  transition: color 0.2s, border-color 0.2s;
}

.nav-btn:hover  { color: #e0e0e0; }
.nav-btn.active {
  color: #ffa500;
  border-bottom-color: #ffa500;
  background: #161616;
}

/* Unsaved-changes indicator on a tab.  A pale-yellow bullet after the
 * label; distinct from the amber .active accent so both can coexist
 * (active tab that also has pending edits). */
.nav-btn.dirty::after {
  content: " \2022";
  color: #ffd84d;
  font-size: 16px;
  line-height: 0;
  vertical-align: baseline;
  margin-left: 2px;
}

/* -------------------------------------------------------------------------
   Tabs
   ------------------------------------------------------------------------- */

.tab {
  padding: 16px;
}
.tab.hidden { display: none; }

/* -------------------------------------------------------------------------
   Dashboard
   ------------------------------------------------------------------------- */

.dash-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(180px, 1fr));
  gap: 12px;
  margin-bottom: 16px;
}

.card {
  background: #161616;
  border: 1px solid #262626;
  border-radius: 10px;
  padding: 16px;
}

.temp-label {
  font-size: 11px;
  color: #888;
  letter-spacing: 0.6px;
  font-weight: 700;
}

.temp-value {
  font-size: 44px;
  font-weight: 700;
  color: #808080;
  margin: 6px 0 8px;
  font-variant-numeric: tabular-nums;
  transition: color 0.25s ease;
}

/* Value color states */
.temp-value.in-range { color: #4ade80; }  /* green */
.temp-value.above    { color: #f87171; }  /* red   */
.temp-value.below    { color: #3399ff; }  /* blue  */
.temp-value.off      { color: #808080; }  /* gray  */

.temp-meta {
  display: flex;
  flex-direction: column;
  gap: 4px;
  margin-top: 4px;
}

.temp-meta-row {
  display: flex;
  justify-content: space-between;
  align-items: baseline;
  gap: 8px;
  font-variant-numeric: tabular-nums;
}

.temp-meta-label {
  font-size: 11px;
  font-weight: 700;
  color: #888;
  letter-spacing: 0.6px;
}

.temp-meta-value {
  font-size: 13px;
  font-weight: 700;
  color: #ccc;
}
/* Amber highlight for the value the loop is actively controlling to:
   - Ambient mode  → ambient target + ambient range
   - Beer/Ramp/Crash → beer target + ambient range
   - Limp-home     → highlight swaps to the AMBIENT target (since the
                     beer sensor is stale and we're holding ambient at
                     the beer target instead)
   The label stays gray so the row still reads cleanly. */
.temp-meta-value.control-target {
  color: #ffa500;
}

/* Sensor-lost hint under the BEER TARGET row.  Small, subdued amber so
   the operator immediately grasps *why* the amber highlight moved to
   the AMBIENT card without the hint stealing focus from the digits. */
.limp-home-hint {
  font-size: 11px;
  font-weight: 600;
  color: #f59e0b;
  margin-top: 4px;
  letter-spacing: 0.3px;
  font-style: italic;
}

.mode-value {
  font-size: 26px;
  font-weight: 700;
  color: #ffa500;
  margin: 6px 0 12px;
  text-transform: uppercase;
}

/* Big dropdown that replaces the old .mode-value on the dashboard.
   Sized to feel like the BEER/AMBIENT temperature values while leaving
   room for the native chevron. */
.mode-select {
  width: 100%;
  font-size: 28px;
  font-weight: 700;
  color: #ffa500;
  background: #1a1a1a;
  border: 1px solid #333;
  border-radius: 8px;
  padding: 6px 12px;
  margin: 6px 0 4px;
  cursor: pointer;
  appearance: none;
  -webkit-appearance: none;
  background-image: linear-gradient(45deg, transparent 50%, #ffa500 50%),
                    linear-gradient(135deg, #ffa500 50%, transparent 50%);
  background-position: calc(100% - 18px) 55%, calc(100% - 12px) 55%;
  background-size: 6px 6px, 6px 6px;
  background-repeat: no-repeat;
  padding-right: 34px;
}
.mode-select:hover, .mode-select:focus {
  border-color: #ffa500;
  outline: none;
}
.mode-select option {
  background: #1a1a1a;
  color: #ffa500;
}

.mode-status {
  font-size: 12px;
  color: #888;
  letter-spacing: 1px;
  text-transform: uppercase;
  text-align: center;
  margin: 4px 0 10px;
  font-weight: 600;
}
.mode-status.running { color: #22c55e; }
.mode-status.stopped { color: #888; }

.dash-buttons {
  display: flex;
  gap: 8px;
  flex-wrap: wrap;
}

.dash-sub {
  font-size: 12px;
  color: #777;
  margin-top: 8px;
  min-height: 15px;
}
.dash-sub.cool-on {
  color: #4a9eff;         /* blue — matches temp-value.below (cold direction) */
  font-weight: 600;
}
.dash-sub.dwell,
.dash-sub.min-on {
  color: #f5a623;         /* amber — compressor dwell holding cool state */
  font-weight: 600;
}
.dash-sub.max-runtime,
.dash-sub.fail-safe {
  color: #ff5c5c;         /* red — max runtime trip or extended lockout */
  font-weight: 600;
}

/* Relays */

.relay-row {
  display: flex;
  gap: 8px;
  flex-wrap: wrap;
  margin: 6px 0;
}

.relay-pill {
  font-size: 12px;
  font-weight: 700;
  padding: 6px 12px;
  border-radius: 6px;
  background: #262626;
  color: #666;
  letter-spacing: 0.4px;
}
.relay-pill.on {
  background: #ffa500;
  color: #0a0a0a;
}

.ramp-card {
  margin-bottom: 12px;
}

.fg-card {
  /* Span the same two grid tracks BEER + AMBIENT occupy so the card
     always visually matches the width of those two cards combined. */
  grid-column: 1 / span 2;
  margin-bottom: 0;
}

/* Trend graph card sits right of the fermentation status card, spanning
   the same two grid tracks CONTROL MODE + RELAYS occupy on the row
   above.  On narrow layouts (single-column stack) the auto-fit grid
   pushes it below and it takes the full width, which is also fine. */
.trend-card {
  grid-column: 3 / span 2;
  margin-bottom: 0;
  display: flex;
  flex-direction: column;
}

.trend-header {
  display: flex;
  justify-content: space-between;
  align-items: baseline;
  gap: 12px;
}

.trend-sub {
  font-size: 11px;
  color: #888;
  font-variant-numeric: tabular-nums;
  letter-spacing: 0.3px;
}

.trend-svg-wrap {
  margin-top: 8px;
  flex: 1;
  min-height: 200px;
  display: flex;
}

#trend-svg {
  width: 100%;
  height: 100%;
  display: block;
  background: #0f0f0f;
  border: 1px solid #1e1e1e;
  border-radius: 6px;
  font: 10px ui-monospace, "SF Mono", Menlo, Consolas, monospace;
}

.trend-empty {
  margin-top: 8px;
  font-size: 12px;
  color: #666;
  font-style: italic;
}
.trend-empty.hidden { display: none; }

/* SVG-internal classes.  Kept here (not in <style> inside the svg)
   so they compose with the site's dark palette in one place. */
.trend-axis {
  stroke: #2a2a2a;
  stroke-width: 1;
}
.trend-tick {
  stroke: #333;
  stroke-width: 1;
}
.trend-tick-label {
  fill: #6a6a6a;
  font-size: 9px;
}
.trend-line {
  fill: none;
  stroke: #4ade80;       /* green — matches "in-range" temp colour */
  stroke-width: 1.5;
  stroke-linejoin: round;
  stroke-linecap: round;
}
.trend-slope {
  stroke: #ffa500;       /* amber — matches CONTROL MODE colour */
  stroke-width: 1.5;
  stroke-dasharray: 6 4;
  opacity: 0.85;
}
.trend-outlier {
  fill: #f87171;         /* red — matches "above" temp colour */
  stroke: #0f0f0f;
  stroke-width: 1;
}

/* State-aware garnish bands.  Drawn under the polyline so the data
   line always wins visual priority.  Fill-opacity kept low so the
   grid ticks and axis labels remain readable through the band. */
.trend-band-stable {
  fill: #4ade80;         /* green — echoes .trend-line for "we're here" */
  fill-opacity: 0.16;
  stroke: #4ade80;
  stroke-opacity: 0.55;
  stroke-width: 1;
  stroke-dasharray: 3 3;
}
.trend-band-jittery {
  fill: #f87171;         /* red — echoes .trend-outlier for "this is bad" */
  fill-opacity: 0.12;
  stroke: #f87171;
  stroke-opacity: 0.45;
  stroke-width: 1;
  stroke-dasharray: 3 3;
}
.trend-band-label {
  fill: #6a6a6a;
  font-size: 9px;
  font-style: italic;
}

.ramp-body, .fg-body {
  font-size: 14px;
  color: #ccc;
  margin-top: 8px;
  line-height: 1.5;
}

.ramp-body {
  white-space: pre-wrap;
}

.fg-body {
  display: flex;
  flex-direction: column;
  gap: 4px;
}

.fg-row {
  display: grid;
  grid-template-columns: 90px 1fr auto;
  align-items: baseline;
  gap: 12px;
}

.fg-key {
  color: #888;
  font-size: 13px;
  text-transform: uppercase;
  letter-spacing: 0.5px;
}

.fg-val {
  color: #eee;
  font-family: ui-monospace, "SF Mono", Menlo, Consolas, monospace;
  font-variant-numeric: tabular-nums;
  font-size: 15px;
}

.fg-val.missing {
  color: #666;
}

/* FG status label colouring.  Green = stable (final gravity reached).
   Amber = active work in progress (still fermenting / settling) — same
   family as the CONTROL MODE amber so it reads consistently.  Red-ish =
   Jittery Readings, which means the sensor probably needs attention.
   Neutral gray = neutral states (not enough data, pending). */
.fg-val.fg-stable {
  color: #4caf50;
  font-weight: 600;
}

.fg-val.fg-fermenting,
.fg-val.fg-settling {
  color: #ffa500;
}

.fg-val.fg-jittery {
  color: #f87171;
}

.fg-val.fg-not-enough {
  color: #d0d0d0;
}

.fg-ts {
  color: #888;
  font-size: 12px;
  font-family: ui-monospace, "SF Mono", Menlo, Consolas, monospace;
  font-variant-numeric: tabular-nums;
  text-align: right;
}

.fg-poll {
  margin-top: 6px;
  padding-top: 6px;
  border-top: 1px solid #2a2a2a;
  color: #888;
  font-size: 12px;
}

/* Amber tint on the poll line whenever BF data is stale -- the newest
   reading is older than api.fg.stale_hours.  Warning color rather than
   red so it doesn't compete with the FAIL-SAFE / emergency indicators. */
.fg-poll.fg-stale {
  color: #d0a04a;
}

/* -------------------------------------------------------------------------
   Forms
   ------------------------------------------------------------------------- */

.settings {
  background: #161616;
  border: 1px solid #262626;
  border-radius: 10px;
  padding: 16px;
}

.settings h3 {
  margin: 20px 0 10px;
  font-size: 13px;
  color: #ffa500;
  letter-spacing: 0.6px;
  font-weight: 700;
}
.settings h3:first-child { margin-top: 0; }

.setting-note {
  font-size: 12px;
  color: #999;
  margin: 0 0 8px 0;
  line-height: 1.4;
}

.setting-subhead {
  font-size: 12px;
  font-weight: 600;
  letter-spacing: 0.08em;
  text-transform: uppercase;
  color: #b8b8b8;
  margin: 12px 0 4px 0;
}

.setting-row {
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 8px 0;
  border-bottom: 1px solid #1f1f1f;
}
.setting-row:last-child { border-bottom: none; }

.setting-row label {
  flex: 0 0 40%;
  font-size: 13px;
  color: #bbb;
}

.setting-row input,
.setting-row select {
  flex: 1;
  padding: 8px 10px;
  border-radius: 6px;
  border: 1px solid #333;
  background: #0f0f0f;
  color: #e0e0e0;
  font-size: 13px;
  font-family: inherit;
}

.setting-row input:focus,
.setting-row select:focus {
  outline: none;
  border-color: #ffa500;
}

.setting-row.static span {
  flex: 1;
  color: #ccc;
  font-size: 13px;
}

.button-row {
  display: flex;
  gap: 10px;
  flex-wrap: wrap;
  margin-top: 16px;
  padding-top: 12px;
  border-top: 1px solid #1f1f1f;
}

/* "Advanced" collapsible on the Updates tab (hosts Force Reinstall etc.). */
.advanced-block {
  margin-top: 22px;
  padding: 12px 14px;
  background: #181818;
  border: 1px solid #262626;
  border-radius: 6px;
  color: #ccc;
  font-size: 13px;
}
.advanced-block > summary {
  cursor: pointer;
  color: #d0a04a;
  font-weight: 600;
  user-select: none;
}
.advanced-block .setting-note {
  margin: 10px 0 4px 0;
}
.advanced-block .button-row {
  margin-top: 8px;
  padding-top: 8px;
  border-top: 1px solid #262626;
}

.btn-primary,
.btn-secondary,
.btn-success,
.btn-danger,
.btn-mini {
  padding: 8px 16px;
  border-radius: 6px;
  border: none;
  font-size: 13px;
  font-weight: 700;
  cursor: pointer;
  letter-spacing: 0.4px;
  transition: filter 0.15s;
}

.btn-primary   { background: #ffa500; color: #0a0a0a; }
.btn-secondary { background: #333;    color: #e0e0e0; }
.btn-success   { background: #22c55e; color: #0a0a0a; }
.btn-danger    { background: #b23434; color: #fff; }
.btn-mini      { background: #2d2d2d; color: #ffa500; font-size: 11px; padding: 6px 10px; }

.btn-primary:hover,
.btn-secondary:hover,
.btn-success:hover,
.btn-danger:hover,
.btn-mini:hover { filter: brightness(1.15); }

/* Save button in a dirty form: subtle yellow ring + soft pulse so the
 * user notices "there are pending changes here" without the button
 * shouting.  Uses outline (doesn't affect layout) rather than border. */
form.form-dirty .btn-primary {
  outline: 2px solid #ffd84d;
  outline-offset: 2px;
  animation: dirty-pulse 1.8s ease-in-out infinite;
}
@keyframes dirty-pulse {
  0%, 100% { box-shadow: 0 0 0 0     rgba(255, 216, 77, 0.00); }
  50%      { box-shadow: 0 0 0 6px   rgba(255, 216, 77, 0.18); }
}

/* Muted disabled state: keep the original hue (so the eye still reads
   green=Run / red=Stop) but drop opacity and kill the hover feedback.
   Applies to any of the button classes via [disabled]. */
.btn-primary[disabled],
.btn-secondary[disabled],
.btn-success[disabled],
.btn-danger[disabled],
.btn-mini[disabled] {
  opacity: 0.35;
  cursor: not-allowed;
  filter: none;
}
.btn-primary[disabled]:hover,
.btn-secondary[disabled]:hover,
.btn-success[disabled]:hover,
.btn-danger[disabled]:hover,
.btn-mini[disabled]:hover { filter: none; }

/* Dashboard Run/Stop share the row equally so they read as a pair. */
.mode-card .dash-buttons { justify-content: stretch; }
.mode-card .dash-buttons > button { flex: 1 1 0; }

.msg {
  margin-top: 10px;
  font-size: 12px;
  min-height: 16px;
}
.msg.ok  { color: #4ade80; }
.msg.err { color: #f87171; }
/* Pinned "operation in flight" style -- soft blue with a subtle pulse
 * so the elapsed-second counter feels alive even when the digit isn't
 * changing rapidly.  Opacity oscillates between 0.65 and 1.0 on a 1.4 s
 * cycle: fast enough to read as "working," slow enough not to distract.
 */
.msg.busy {
  color: #60a5fa;
  animation: msg-busy-pulse 1.4s ease-in-out infinite;
}
@keyframes msg-busy-pulse {
  0%, 100% { opacity: 1; }
  50%      { opacity: 0.65; }
}

.result {
  background: #0a0a0a;
  border: 1px solid #262626;
  border-radius: 6px;
  padding: 12px;
  font-size: 12px;
  color: #ccc;
  white-space: pre-wrap;
  max-height: 300px;
  overflow: auto;
  margin-top: 12px;
}

/* OTA install progress bar */
.ota-progress-bar {
  height: 8px;
  background: #1a1a1a;
  border: 1px solid #262626;
  border-radius: 4px;
  overflow: hidden;
  margin-top: 12px;
}

.ota-progress-fill {
  height: 100%;
  width: 0;
  background: linear-gradient(90deg, #4ade80, #22c55e);
  transition: width 0.3s ease;
}

.ota-banner {
  margin-top: 12px;
  padding: 14px 18px;
  border-radius: 6px;
  font-size: 15px;
  font-weight: 600;
  text-align: center;
  border: 1px solid transparent;
}

.ota-banner.hidden { display: none; }

.ota-banner.success {
  background: rgba(74, 222, 128, 0.12);
  border-color: #22c55e;
  color: #86efac;
}

.ota-banner.failure {
  background: rgba(248, 113, 113, 0.12);
  border-color: #ef4444;
  color: #fca5a5;
}

.ota-banner.warning {
  background: rgba(251, 191, 36, 0.12);
  border-color: #f59e0b;
  color: #fcd34d;
}

.ota-banner .banner-countdown {
  font-weight: 400;
  font-size: 13px;
  margin-top: 6px;
  opacity: 0.85;
}

/* Utility: also hide non-.tab elements when .hidden class is applied. */
.hidden { display: none !important; }

/* -------------------------------------------------------------------------
   About
   ------------------------------------------------------------------------- */

.about {
  background: #161616;
  border: 1px solid #262626;
  border-radius: 10px;
  padding: 24px;
  text-align: center;
}
.about h2 { color: #ffa500; margin-top: 0; }
.about p  { line-height: 1.6; color: #ccc; }
.copyright { color: #777; font-size: 12px; margin-top: 30px; }
.footnote  { color: #555; font-size: 11px; }

/* -------------------------------------------------------------------------
   Modal dialog (OTA "monitoring is active" confirmation)

   A single reusable overlay pattern.  The card is centered, capped at
   ~480 px wide, and picks up the same amber accent as .btn-primary /
   nav-btn.active so it visually belongs to the rest of the app.  The
   button row stacks vertically because the labels are long ("Stop,
   Update, Restart Monitoring") and horizontal packing looks cramped.
   ------------------------------------------------------------------------- */

.modal-overlay {
  position: fixed;
  inset: 0;
  background: rgba(0, 0, 0, 0.78);
  display: flex;
  align-items: center;
  justify-content: center;
  padding: 20px;
  z-index: 1000;
}
.modal-overlay.hidden { display: none; }

.modal-card {
  background: #181818;
  border: 1px solid #333;
  border-left: 4px solid #ffa500;
  border-radius: 8px;
  max-width: 480px;
  width: 100%;
  padding: 24px;
  box-shadow: 0 10px 40px rgba(0, 0, 0, 0.6);
}

.modal-title {
  margin: 0 0 12px 0;
  font-size: 18px;
  color: #ffa500;
  letter-spacing: 0.4px;
}

.modal-body {
  color: #e0e0e0;
  font-size: 14px;
  line-height: 1.5;
  margin: 0 0 20px 0;
}
.modal-body strong { color: #ffa500; }

.modal-buttons {
  display: flex;
  flex-direction: column;
  gap: 10px;
  margin-bottom: 16px;
}
.modal-buttons button {
  width: 100%;
  padding: 12px 16px;
  font-size: 13px;
  text-align: center;
}

.modal-note {
  color: #888;
  font-size: 12px;
  line-height: 1.4;
  margin: 0;
}
